  public void UpdateCompactPermissions(Dictionary<string, int> permissions)
  {
    this._compactPermissions = new Dictionary<string, int>((IDictionary<string, int>) permissions);
    if (!this._compactLayout)
      return;
    ProtoId<SpeciesPrototype>? species = this.Profile?.Species;
    ProtoId<SpeciesPrototype>? nullable = ProtoId<SpeciesPrototype>.op_Implicit("Felinid");
    if ((species.HasValue == nullable.HasValue ? (species.HasValue ? (ProtoId<SpeciesPrototype>.op_Equality(species.GetValueOrDefault(), nullable.GetValueOrDefault()) ? 1 : 0) : 1) : 0) != 0 && !this.HasCompactFelinidPermission())
      this.SetCompactSpecies("Human");
    else
      this.UpdateCompactSpeciesButtons();
  }

  public void RefreshFlavorText()
  {
    if (this._allowFlavorText)
    {
      if (this._flavorText != null)
        return;
      this._flavorText = new Content.Client.FlavorText.FlavorText();
      ((Control) this.TabContainer).AddChild((Control) this._flavorText);
      this.TabContainer.SetTabTitle(((Control) this.TabContainer).ChildCount - 1, Loc.GetString("humanoid-profile-editor-flavortext-tab"));
      this._flavorTextEdit = this._flavorText.CFlavorTextInput;
      this._flavorText.OnFlavorTextChanged += new Action<string>(this.OnFlavorTextChange);
      if (!this._compactLayout)
        return;
      TabContainer.SetTabVisible((Control) this._flavorText, false);
    }
    else
    {
      if (this._flavorText == null)
        return;
      ((Control) this.TabContainer).RemoveChild((Control) this._flavorText);
      this._flavorText.OnFlavorTextChanged -= new Action<string>(this.OnFlavorTextChange);
      this._flavorText.Orphan();
      this._flavorTextEdit = (TextEdit) null;
      this._flavorText = (Content.Client.FlavorText.FlavorText) null;
    }
  }

  public void RefreshTraits()
  {
    ((Control) this.TraitsList).DisposeAllChildren();
    List<TraitPrototype> list = this._prototypeManager.EnumeratePrototypes<TraitPrototype>().OrderBy<TraitPrototype, string>((Func<TraitPrototype, string>) (t => Loc.GetString(LocId.op_Implicit(t.Name)))).ToList<TraitPrototype>();
    this.TabContainer.SetTabTitle(3, Loc.GetString("humanoid-profile-editor-traits-tab"));
    if (list.Count < 1)
    {
      ((Control) this.TraitsList).AddChild((Control) new Label()
      {
        Text = Loc.GetString("humanoid-profile-editor-no-traits"),
        FontColorOverride = new Color?(Color.Gray)
      });
    }
    else
    {
      Dictionary<string, List<string>> dictionary1 = new Dictionary<string, List<string>>();
      List<string> stringList1 = new List<string>();
      dictionary1.Add("Default", stringList1);
      foreach (TraitPrototype traitPrototype in list)
      {
        if (!traitPrototype.Category.HasValue)
          stringList1.Add(traitPrototype.ID);
        else if (this._prototypeManager.HasIndex<TraitCategoryPrototype>(traitPrototype.Category))
        {
          Dictionary<string, List<string>> dictionary2 = dictionary1;
          ProtoId<TraitCategoryPrototype>? category = traitPrototype.Category;
          string str = category.HasValue ? ProtoId<TraitCategoryPrototype>.op_Implicit(category.GetValueOrDefault()) : (string) null;
          Extensions.GetOrNew<string, List<string>>(dictionary2, str).Add(traitPrototype.ID);
        }
      }
      foreach ((string key, List<string> stringList2) in dictionary1)
      {
        TraitCategoryPrototype categoryPrototype = (TraitCategoryPrototype) null;
        if (key != "Default")
        {
          categoryPrototype = this._prototypeManager.Index<TraitCategoryPrototype>(key);
          BoxContainer traitsList = this.TraitsList;
          Label label = new Label();
          label.Text = Loc.GetString(LocId.op_Implicit(categoryPrototype.Name));
          ((Control) label).Margin = new Thickness(0.0f, 10f, 0.0f, 0.0f);
          ((Control) label).StyleClasses.Add("LabelHeading");
          ((Control) traitsList).AddChild((Control) label);
        }
        List<TraitPreferenceSelector> preferenceSelectorList = new List<TraitPreferenceSelector>();
        int num1 = 0;
        foreach (string str in stringList2)
        {
          TraitPrototype trait = this._prototypeManager.Index<TraitPrototype>(str);
          TraitPreferenceSelector preferenceSelector1 = new TraitPreferenceSelector(trait);
          TraitPreferenceSelector preferenceSelector2 = preferenceSelector1;
          HumanoidCharacterProfile profile = this.Profile;
          int num2 = profile != null ? (profile.TraitPreferences.Contains(ProtoId<TraitPrototype>.op_Implicit(trait.ID)) ? 1 : 0) : 0;
          preferenceSelector2.Preference = num2 != 0;
          if (preferenceSelector1.Preference)
            num1 += trait.Cost;
          preferenceSelector1.PreferenceChanged += (Action<bool>) (preference =>
          {
            this.Profile = !preference ? this.Profile?.WithoutTraitPreference(ProtoId<TraitPrototype>.op_Implicit(trait.ID), this._prototypeManager) : this.Profile?.WithTraitPreference(ProtoId<TraitPrototype>.op_Implicit(trait.ID), this._prototypeManager);
            this.SetDirty();
            this.RefreshTraits();
          });
          preferenceSelectorList.Add(preferenceSelector1);
        }
        int? maxTraitPoints;
        if (categoryPrototype != null)
        {
          maxTraitPoints = categoryPrototype.MaxTraitPoints;
          if (maxTraitPoints.HasValue && maxTraitPoints.GetValueOrDefault() >= 0)
            ((Control) this.TraitsList).AddChild((Control) new Label()
            {
              Text = Loc.GetString("humanoid-profile-editor-trait-count-hint", new (string, object)[2]
              {
                ("current", (object) num1),
                ("max", (object) categoryPrototype.MaxTraitPoints)
              }),
              FontColorOverride = new Color?(Color.Gray)
            });
        }
        foreach (TraitPreferenceSelector preferenceSelector in preferenceSelectorList)
        {
          if (preferenceSelector != null)
          {
            if (categoryPrototype != null)
            {
              maxTraitPoints = categoryPrototype.MaxTraitPoints;
              if (maxTraitPoints.HasValue && maxTraitPoints.GetValueOrDefault() >= 0)
              {
                int num3 = preferenceSelector.Cost + num1;
                maxTraitPoints = categoryPrototype.MaxTraitPoints;
                int valueOrDefault = maxTraitPoints.GetValueOrDefault();
                if (num3 > valueOrDefault & maxTraitPoints.HasValue)
                  preferenceSelector.Checkbox.Label.FontColorOverride = new Color?(Color.Red);
              }
            }
            ((Control) this.TraitsList).AddChild((Control) preferenceSelector);
          }
        }
      }
    }
  }

  public void RefreshSpecies()
  {
    if (this._compactLayout)
    {
      this.UpdateCompactSpeciesButtons();
      if (this.Profile != null && ProtoId<SpeciesPrototype>.op_Inequality(this.Profile.Species, ProtoId<SpeciesPrototype>.op_Implicit("Human")) && ProtoId<SpeciesPrototype>.op_Inequality(this.Profile.Species, ProtoId<SpeciesPrototype>.op_Implicit("Felinid")))
      {
        this.SetSpecies("Human");
      }
      else
      {
        ProtoId<SpeciesPrototype>? species = this.Profile?.Species;
        ProtoId<SpeciesPrototype>? nullable = ProtoId<SpeciesPrototype>.op_Implicit("Felinid");
        if ((species.HasValue == nullable.HasValue ? (species.HasValue ? (ProtoId<SpeciesPrototype>.op_Equality(species.GetValueOrDefault(), nullable.GetValueOrDefault()) ? 1 : 0) : 1) : 0) == 0 || this.HasCompactFelinidPermission())
          return;
        this.SetSpecies("Human");
      }
    }
    else
    {
      this.SpeciesButton.Clear();
      this._species.Clear();
      this._species.AddRange(this._prototypeManager.EnumeratePrototypes<SpeciesPrototype>().Where<SpeciesPrototype>((Func<SpeciesPrototype, bool>) (o => o.RoundStart)));
      List<string> list = this._species.Select<SpeciesPrototype, string>((Func<SpeciesPrototype, string>) (o => o.ID)).ToList<string>();
      for (int index = 0; index < this._species.Count; ++index)
      {
        this.SpeciesButton.AddItem(Loc.GetString(this._species[index].Name), new int?(index));
        HumanoidCharacterProfile profile = this.Profile;
        if ((profile != null ? (profile.Species.Equals(this._species[index].ID) ? 1 : 0) : 0) != 0)
          this.SpeciesButton.SelectId(index);
      }
      if (this.Profile == null || list.Contains(ProtoId<SpeciesPrototype>.op_Implicit(this.Profile.Species)))
        return;
      this.SetSpecies(ProtoId<SpeciesPrototype>.op_Implicit(SharedHumanoidAppearanceSystem.DefaultSpecies));
    }
  }

  public void RefreshAntags()
  {
    ((Control) this.AntagList).DisposeAllChildren();
    (string, int)[] items = new (string, int)[2]
    {
      ("humanoid-profile-editor-antag-preference-yes-button", 0),
      ("humanoid-profile-editor-antag-preference-no-button", 1)
    };
    foreach (AntagPrototype antagPrototype in (IEnumerable<AntagPrototype>) this._prototypeManager.EnumerateCM<AntagPrototype>().OrderBy<AntagPrototype, string>((Func<AntagPrototype, string>) (a => Loc.GetString(a.Name))))
    {
      AntagPrototype antag = antagPrototype;
      if (antag.SetPreference)
      {
        BoxContainer boxContainer1 = new BoxContainer()
        {
          Orientation = (BoxContainer.LayoutOrientation) 0
        };
        RequirementsSelector requirementsSelector1 = new RequirementsSelector();
        ((Control) requirementsSelector1).Margin = new Thickness(3f, 3f, 3f, 0.0f);
        RequirementsSelector requirementsSelector2 = requirementsSelector1;
        requirementsSelector2.OnOpenGuidebook += this.OnOpenGuidebook;
        string title = Loc.GetString(antag.Name);
        string description = Loc.GetString(antag.Objective);
        requirementsSelector2.Setup(items, title, 250, description, guides: antag.Guides);
        RequirementsSelector requirementsSelector3 = requirementsSelector2;
        HumanoidCharacterProfile profile = this.Profile;
        int id = (profile != null ? (profile.AntagPreferences.Contains(ProtoId<AntagPrototype>.op_Implicit(antag.ID)) ? 1 : 0) : 0) == 0 ? 1 : 0;
        requirementsSelector3.Select(id);
        FormattedMessage reason;
        if (!this._requirements.CheckRoleRequirements(this._entManager.System<SharedRoleSystem>().GetAntagRequirement(antag), (HumanoidCharacterProfile) this._preferencesManager.Preferences?.SelectedCharacter, out reason))
        {
          requirementsSelector2.LockRequirements(reason);
          this.Profile = this.Profile?.WithAntagPreference(ProtoId<AntagPrototype>.op_Implicit(antag.ID), false);
          this.SetDirty();
        }
        else
          requirementsSelector2.UnlockRequirements();
        requirementsSelector2.OnSelected += (Action<int>) (preference =>
        {
          this.Profile = this.Profile?.WithAntagPreference(ProtoId<AntagPrototype>.op_Implicit(antag.ID), preference == 0);
          this.SetDirty();
        });
        ((Control) boxContainer1).AddChild((Control) requirementsSelector2);
        BoxContainer boxContainer2 = boxContainer1;
        Button button = new Button();
        ((BaseButton) button).Disabled = true;
        button.Text = Loc.GetString("loadout-window");
        ((Control) button).HorizontalAlignment = (Control.HAlignment) 3;
        ((Control) button).Margin = new Thickness(3f, 0.0f, 0.0f, 0.0f);
        ((Control) boxContainer2).AddChild((Control) button);
        ((Control) this.AntagList).AddChild((Control) boxContainer1);
      }
    }
  }

  private void SetDirty()
  {
    if (this.Profile != null)
    {
      PlayerPreferences preferences = this._preferencesManager.Preferences;
      if ((preferences != null ? (preferences.SelectedCharacter.MemberwiseEquals((ICharacterProfile) this.Profile) ? 1 : 0) : 0) == 0)
      {
        this.IsDirty = true;
        return;
      }
    }
    this.IsDirty = false;
  }

  public void RefreshLoadouts() => ((Control) this._loadoutWindow)?.Orphan();

  public void RefreshRMC(SharedRMCPatronTier? tier)
  {
    if (this._compactLayout)
      this.TabContainer.SetTabVisible(5, false);
    else
      this.TabContainer.SetTabVisible(5, (object) tier != null && tier.NamedItems);
  }

  private void ReloadPreview()
  {
    this._entManager.DeleteEntity(new EntityUid?(this.PreviewDummy));
    this.PreviewDummy = EntityUid.Invalid;
    if (this.Profile == null || !this._prototypeManager.HasIndex<SpeciesPrototype>(this.Profile.Species))
      return;
    this.PreviewDummy = this._controller.LoadProfileEntity(this.Profile, this.JobOverride, ((BaseButton) this.ShowClothes).Pressed);
    this.SpriteView.SetEntity(new EntityUid?(this.PreviewDummy));
    this._entManager.System<MetaDataSystem>().SetEntityName(this.PreviewDummy, this.Profile.Name, (MetaDataComponent) null, true);
    this.SetDirty();
  }

  public void ResetToDefault()
  {
    this.SetProfile((HumanoidCharacterProfile) this._preferencesManager.Preferences?.SelectedCharacter, this._preferencesManager.Preferences?.SelectedCharacterIndex);
  }

  public void SetProfile(HumanoidCharacterProfile? profile, int? slot)
  {
    this.Profile = profile?.Clone();
    this.CharacterSlot = slot;
    this.IsDirty = false;
    this.JobOverride = (JobPrototype) null;
    if (this._compactLayout && this.Profile != null && ((ProtoId<SpeciesPrototype>.op_Equality(this.Profile.Species, ProtoId<SpeciesPrototype>.op_Implicit("Human")) ? 1 : (ProtoId<SpeciesPrototype>.op_Equality(this.Profile.Species, ProtoId<SpeciesPrototype>.op_Implicit("Felinid")) ? 1 : 0)) == 0 || ProtoId<SpeciesPrototype>.op_Equality(this.Profile.Species, ProtoId<SpeciesPrototype>.op_Implicit("Felinid")) && !this.HasCompactFelinidPermission()))
      this.Profile = this.Profile.WithSpecies("Human");
    this.UpdateNameEdit();
    this.UpdateFlavorTextEdit();
    this.UpdateSexControls();
    this.UpdateGenderControls();
    this.UpdateTTSVoicesControls();
    this.UpdateSkinColor();
    this.UpdateSpawnPriorityControls();
    this.UpdateArmorPreferenceControls();
    this.UpdateSquadPreferenceControls();
    this.UpdateAgeEdit();
    this.UpdateEyePickers();
    this.UpdateSaveButton();
    this.UpdateMarkings();
    this.UpdateHairPickers();
    this.UpdateCMarkingsHair();
    this.UpdateCMarkingsFacialHair();
    this.UpdateNamedItems();
    this.UpdatePlaytimePerks();
    this.UpdateXenoPrefix();
    this.UpdateXenoPostfix();
    this.RefreshAntags();
    this.RefreshJobs();
    this.RefreshLoadouts();
    this.RefreshSpecies();
    this.RefreshTraits();
    this.RefreshFlavorText();
    this.ReloadPreview();
    if (this.Profile != null)
