  private void OnSpeciesInfoButtonPressed(BaseButton.ButtonEventArgs args)
  {
    GuidebookUIController uiController = ((Control) this).UserInterfaceManager.GetUIController<GuidebookUIController>();
    HumanoidCharacterProfile profile = this.Profile;
    ProtoId<SpeciesPrototype> protoId1 = profile != null ? profile.Species : SharedHumanoidAppearanceSystem.DefaultSpecies;
    ProtoId<GuideEntryPrototype> protoId2 = HumanoidProfileEditor.DefaultSpeciesGuidebook;
    if (this._prototypeManager.HasIndex<GuideEntryPrototype>(ProtoId<SpeciesPrototype>.op_Implicit(protoId1)))
      protoId2 = new ProtoId<GuideEntryPrototype>(protoId1.Id);
    GuideEntryPrototype guideEntryPrototype;
    if (!this._prototypeManager.TryIndex<GuideEntryPrototype>(HumanoidProfileEditor.DefaultSpeciesGuidebook, ref guideEntryPrototype))
      return;
    Dictionary<ProtoId<GuideEntryPrototype>, GuideEntry> dictionary = new Dictionary<ProtoId<GuideEntryPrototype>, GuideEntry>();
    dictionary.Add(HumanoidProfileEditor.DefaultSpeciesGuidebook, (GuideEntry) guideEntryPrototype);
    GuidebookUIController guidebookUiController = uiController;
    Dictionary<ProtoId<GuideEntryPrototype>, GuideEntry> guides = dictionary;
    ProtoId<GuideEntryPrototype>? nullable = new ProtoId<GuideEntryPrototype>?(protoId2);
    ProtoId<GuideEntryPrototype>? forceRoot = new ProtoId<GuideEntryPrototype>?();
    ProtoId<GuideEntryPrototype>? selected = nullable;
    guidebookUiController.OpenGuidebook(guides, forceRoot: forceRoot, selected: selected);
  }

  public void RefreshJobs()
  {
    ((Control) this.JobList).DisposeAllChildren();
    this._jobCategories.Clear();
    this._jobPriorities.Clear();
    bool flag = true;
    List<DepartmentPrototype> departmentPrototypeList = new List<DepartmentPrototype>();
    foreach (DepartmentPrototype enumeratePrototype in this._prototypeManager.EnumeratePrototypes<DepartmentPrototype>())
    {
      if (!enumeratePrototype.EditorHidden)
        departmentPrototypeList.Add(enumeratePrototype);
    }
    departmentPrototypeList.Sort((IComparer<DepartmentPrototype>) DepartmentUIComparer.Instance);
    (string, int)[] items = new (string, int)[4]
    {
      ("humanoid-profile-editor-job-priority-never-button", 0),
      ("humanoid-profile-editor-job-priority-low-button", 1),
      ("humanoid-profile-editor-job-priority-medium-button", 2),
      ("humanoid-profile-editor-job-priority-high-button", 3)
    };
    foreach (DepartmentPrototype departmentPrototype in departmentPrototypeList)
    {
      string str1 = Loc.GetString(LocId.op_Implicit(departmentPrototype.Name));
      BoxContainer boxContainer1;
      if (!this._jobCategories.TryGetValue(departmentPrototype.ID, out boxContainer1))
      {
        BoxContainer boxContainer2 = new BoxContainer();
        boxContainer2.Orientation = (BoxContainer.LayoutOrientation) 1;
        ((Control) boxContainer2).Name = departmentPrototype.ID;
        ((Control) boxContainer2).ToolTip = Loc.GetString("humanoid-profile-editor-jobs-amount-in-department-tooltip", new (string, object)[1]
        {
          ("departmentName", (object) str1)
        });
        boxContainer1 = boxContainer2;
        ((Control) boxContainer1).Visible = departmentPrototype.IsCM && !departmentPrototype.Hidden;
        if (flag && ((Control) boxContainer1).Visible)
          flag = false;
        else
          ((Control) boxContainer1).AddChild(new Control()
          {
            MinSize = new Vector2(0.0f, 23f)
          });
        BoxContainer boxContainer3 = boxContainer1;
        PanelContainer panelContainer1 = new PanelContainer();
        panelContainer1.PanelOverride = (StyleBox) new StyleBoxFlat()
        {
          BackgroundColor = Color.FromHex((ReadOnlySpan<char>) "#464966", new Color?())
        };
        Control.OrderedChildCollection children = ((Control) panelContainer1).Children;
        Label label1 = new Label();
        Label label2 = label1;
        string customName = departmentPrototype.CustomName;
        if (customName == null)
          customName = Loc.GetString("humanoid-profile-editor-department-jobs-label", new (string, object)[1]
          {
            ("departmentName", (object) str1)
          });
        label2.Text = customName;
        ((Control) label1).Margin = new Thickness(5f, 0.0f, 0.0f, 0.0f);
        Label label3 = label1;
        children.Add((Control) label3);
        PanelContainer panelContainer2 = panelContainer1;
        ((Control) boxContainer3).AddChild((Control) panelContainer2);
        this._jobCategories[departmentPrototype.ID] = boxContainer1;
        ((Control) this.JobList).AddChild((Control) boxContainer1);
      }
      JobPrototype[] array = departmentPrototype.Roles.Select<ProtoId<JobPrototype>, JobPrototype>((Func<ProtoId<JobPrototype>, JobPrototype>) (jobId => this._prototypeManager.Index<JobPrototype>(jobId))).Where<JobPrototype>((Func<JobPrototype, bool>) (job => job.SetPreference)).Where<JobPrototype>((Func<JobPrototype, bool>) (job => !job.Hidden)).ToArray<JobPrototype>();
      Array.Sort<JobPrototype>(array, (IComparer<JobPrototype>) JobUIComparer.Instance);
      foreach (JobPrototype jobPrototype in array)
      {
        JobPrototype job = jobPrototype;
        BoxContainer boxContainer4 = new BoxContainer()
        {
          Orientation = (BoxContainer.LayoutOrientation) 0
        };
        RequirementsSelector requirementsSelector1 = new RequirementsSelector();
        ((Control) requirementsSelector1).Margin = new Thickness(3f, 3f, 3f, 0.0f);
        RequirementsSelector requirementsSelector2 = requirementsSelector1;
        requirementsSelector2.OnOpenGuidebook += this.OnOpenGuidebook;
        TextureRect textureRect = new TextureRect();
        textureRect.TextureScale = new Vector2(2f, 2f);
        ((Control) textureRect).VerticalAlignment = (Control.VAlignment) 2;
        TextureRect icon = textureRect;
        JobIconPrototype jobIconPrototype = this._prototypeManager.Index<JobIconPrototype>(job.Icon);
        icon.Texture = this._sprite.Frame0(jobIconPrototype.Icon);
        requirementsSelector2.Setup(items, job.LocalizedName, 200, job.LocalizedDescription, icon, job.Guides);
        FormattedMessage reason;
        if (!this._requirements.IsAllowed(job, (HumanoidCharacterProfile) this._preferencesManager.Preferences?.SelectedCharacter, out reason))
          requirementsSelector2.LockRequirements(reason);
        else
          requirementsSelector2.UnlockRequirements();
        requirementsSelector2.OnSelected += (Action<int>) (selectedPrio =>
        {
          JobPriority priority = (JobPriority) selectedPrio;
          this.Profile = this.Profile?.WithJobPriority(ProtoId<JobPrototype>.op_Implicit(job.ID), priority);
          foreach ((string str2, RequirementsSelector requirementsSelector3) in this._jobPriorities)
          {
            if (str2 == job.ID)
              requirementsSelector3.Select(selectedPrio);
            else if (priority == JobPriority.High && requirementsSelector3.Selected == 3)
            {
              requirementsSelector3.Select(2);
              this.Profile = this.Profile?.WithJobPriority(ProtoId<JobPrototype>.op_Implicit(str2), JobPriority.Medium);
            }
          }
          this.ReloadPreview();
          this.UpdateJobPriorities();
          this.SetDirty();
        });
        Button button1 = new Button();
        button1.Text = Loc.GetString("loadout-window");
        ((Control) button1).HorizontalAlignment = (Control.HAlignment) 3;
        ((Control) button1).VerticalAlignment = (Control.VAlignment) 2;
        ((Control) button1).Margin = new Thickness(3f, 3f, 0.0f, 0.0f);
        Button button2 = button1;
        RoleLoadoutPrototype roleLoadoutProto;
        if (!IoCManager.Instance.Resolve<IPrototypeManager>().TryIndex<RoleLoadoutPrototype>(LoadoutSystem.GetJobPrototype(job.ID), ref roleLoadoutProto))
          ((BaseButton) button2).Disabled = true;
        else
          ((BaseButton) button2).OnPressed += (Action<BaseButton.ButtonEventArgs>) (args =>
          {
            RoleLoadout roleLoadout1 = (RoleLoadout) null;
            this.Profile?.Loadouts.TryGetValue(LoadoutSystem.GetJobPrototype(job.ID), out roleLoadout1);
            RoleLoadout roleLoadout2 = roleLoadout1?.Clone();
            if (roleLoadout2 == null)
            {
              roleLoadout2 = new RoleLoadout(ProtoId<RoleLoadoutPrototype>.op_Implicit(roleLoadoutProto.ID));
              roleLoadout2.SetDefault(this.Profile, ((ISharedPlayerManager) this._playerManager).LocalSession, this._prototypeManager);
            }
            this.OpenLoadout(job, roleLoadout2, roleLoadoutProto);
          });
        this._jobPriorities.Add((job.ID, requirementsSelector2));
        ((Control) boxContainer4).AddChild((Control) requirementsSelector2);
        ((Control) boxContainer4).AddChild((Control) button2);
        ((Control) boxContainer1).AddChild((Control) boxContainer4);
      }
    }
    this.UpdateJobPriorities();
  }

  private void OpenLoadout(
    JobPrototype? jobProto,
    RoleLoadout roleLoadout,
    RoleLoadoutPrototype roleLoadoutProto)
  {
    ((Control) this._loadoutWindow)?.Orphan();
    this._loadoutWindow = (LoadoutWindow) null;
    IDependencyCollection collection = IoCManager.Instance;
    if (collection == null || ((ISharedPlayerManager) this._playerManager).LocalSession == null || this.Profile == null)
      return;
    this.JobOverride = jobProto;
    ICommonSession session = ((ISharedPlayerManager) this._playerManager).LocalSession;
    LoadoutWindow loadoutWindow = new LoadoutWindow(this.Profile, roleLoadout, roleLoadoutProto, ((ISharedPlayerManager) this._playerManager).LocalSession, collection);
    loadoutWindow.Title = jobProto?.ID + "-loadout";
    this._loadoutWindow = loadoutWindow;
    this._loadoutWindow.RefreshLoadouts(roleLoadout, session, collection);
    this._loadoutWindow.OpenCenteredLeft();
    this._loadoutWindow.OnNameChanged += (Action<string>) (name =>
    {
      roleLoadout.EntityName = name;
      this.Profile = this.Profile.WithLoadout(roleLoadout);
      this.SetDirty();
    });
    this._loadoutWindow.OnLoadoutPressed += (Action<ProtoId<LoadoutGroupPrototype>, ProtoId<LoadoutPrototype>>) ((loadoutGroup, loadoutProto) =>
    {
      roleLoadout.AddLoadout(loadoutGroup, loadoutProto, this._prototypeManager);
      this._loadoutWindow.RefreshLoadouts(roleLoadout, session, collection);
      this.Profile = this.Profile?.WithLoadout(roleLoadout);
      this.ReloadPreview();
    });
    this._loadoutWindow.OnLoadoutUnpressed += (Action<ProtoId<LoadoutGroupPrototype>, ProtoId<LoadoutPrototype>>) ((loadoutGroup, loadoutProto) =>
    {
      roleLoadout.RemoveLoadout(loadoutGroup, loadoutProto, this._prototypeManager);
      this._loadoutWindow.RefreshLoadouts(roleLoadout, session, collection);
      this.Profile = this.Profile?.WithLoadout(roleLoadout);
      this.ReloadPreview();
    });
    this.JobOverride = jobProto;
    this.ReloadPreview();
    this._loadoutWindow.OnClose += (Action) (() =>
    {
      this.JobOverride = (JobPrototype) null;
      this.ReloadPreview();
    });
    if (this.Profile == null)
      return;
    this.UpdateJobPriorities();
  }

