  private void OnSkinColorOnValueChanged()
  {
    if (this.Profile == null)
      return;
    switch (this._prototypeManager.Index<SpeciesPrototype>(this.Profile.Species).SkinColoration)
    {
      case HumanoidSkinColor.HumanToned:
        if (!((Control) this.Skin).Visible)
        {
          ((Control) this.Skin).Visible = true;
          ((Control) this.RgbSkinColorContainer).Visible = false;
        }
        Color newColor1 = SkinColor.HumanSkinTone((int) ((Range) this.Skin).Value);
        this.Markings.CurrentSkinColor = newColor1;
        this.Profile = this.Profile.WithCharacterAppearance(this.Profile.Appearance.WithSkinColor(newColor1));
        break;
      case HumanoidSkinColor.Hues:
        if (!((Control) this.RgbSkinColorContainer).Visible)
        {
          ((Control) this.Skin).Visible = false;
          ((Control) this.RgbSkinColorContainer).Visible = true;
        }
        this.Markings.CurrentSkinColor = this._rgbSkinColorSelector.Color;
        this.Profile = this.Profile.WithCharacterAppearance(this.Profile.Appearance.WithSkinColor(this._rgbSkinColorSelector.Color));
        break;
      case HumanoidSkinColor.VoxFeathers:
        if (!((Control) this.RgbSkinColorContainer).Visible)
        {
          ((Control) this.Skin).Visible = false;
          ((Control) this.RgbSkinColorContainer).Visible = true;
        }
        Color newColor2 = SkinColor.ClosestVoxColor(this._rgbSkinColorSelector.Color);
        this.Markings.CurrentSkinColor = newColor2;
        this.Profile = this.Profile.WithCharacterAppearance(this.Profile.Appearance.WithSkinColor(newColor2));
        break;
      case HumanoidSkinColor.TintedHues:
        if (!((Control) this.RgbSkinColorContainer).Visible)
        {
          ((Control) this.Skin).Visible = false;
          ((Control) this.RgbSkinColorContainer).Visible = true;
        }
        Color newColor3 = SkinColor.TintedHues(this._rgbSkinColorSelector.Color);
        this.Markings.CurrentSkinColor = newColor3;
        this.Profile = this.Profile.WithCharacterAppearance(this.Profile.Appearance.WithSkinColor(newColor3));
        break;
    }
    this.ReloadProfilePreview();
  }

