  private void UpdateSexControls()
  {
    if (this.Profile == null)
      return;
    this.SexButton.Clear();
    List<Sex> sexList = new List<Sex>();
    SpeciesPrototype speciesPrototype;
    if (this._prototypeManager.TryIndex<SpeciesPrototype>(this.Profile.Species, ref speciesPrototype))
    {
      foreach (Sex sex in speciesPrototype.Sexes)
        sexList.Add(sex);
    }
    else
      sexList.Add(Sex.Unsexed);
    foreach (Sex sex in sexList)
      this.SexButton.AddItem(Loc.GetString($"humanoid-profile-editor-sex-{sex.ToString().ToLower()}-text"), new int?((int) sex));
    if (sexList.Contains(this.Profile.Sex))
      this.SexButton.SelectId((int) this.Profile.Sex);
    else
      this.SexButton.SelectId((int) sexList[0]);
  }

  private void UpdateSkinColor()
  {
    if (this.Profile == null)
      return;
    switch (this._prototypeManager.Index<SpeciesPrototype>(this.Profile.Species).SkinColoration)
    {
      case HumanoidSkinColor.HumanToned:
        if (!((Control) this.Skin).Visible)
        {
          ((Control) this.Skin).Visible = true;
          ((Control) this.RgbSkinColorContainer).Visible = false;
        }
        ((Range) this.Skin).Value = SkinColor.HumanSkinToneFromColor(this.Profile.Appearance.SkinColor);
        break;
      case HumanoidSkinColor.Hues:
        if (!((Control) this.RgbSkinColorContainer).Visible)
        {
          ((Control) this.Skin).Visible = false;
          ((Control) this.RgbSkinColorContainer).Visible = true;
        }
        this._rgbSkinColorSelector.Color = this.Profile.Appearance.SkinColor;
        break;
      case HumanoidSkinColor.VoxFeathers:
        if (!((Control) this.RgbSkinColorContainer).Visible)
        {
          ((Control) this.Skin).Visible = false;
          ((Control) this.RgbSkinColorContainer).Visible = true;
        }
        this._rgbSkinColorSelector.Color = SkinColor.ClosestVoxColor(this.Profile.Appearance.SkinColor);
        break;
      case HumanoidSkinColor.TintedHues:
        if (!((Control) this.RgbSkinColorContainer).Visible)
        {
          ((Control) this.Skin).Visible = false;
          ((Control) this.RgbSkinColorContainer).Visible = true;
        }
        this._rgbSkinColorSelector.Color = this.Profile.Appearance.SkinColor;
        break;
    }
  }

