    Color? nullable = new Color?();
    MarkingPrototype prototype;
    if (ProtoId<MarkingPrototype>.op_Inequality(ProtoId<MarkingPrototype>.op_Implicit(this.Profile.Appearance.HairStyleId), HairStyles.DefaultHairStyle) && this._markingManager.Markings.TryGetValue(this.Profile.Appearance.HairStyleId, out prototype) && this._markingManager.CanBeApplied(ProtoId<SpeciesPrototype>.op_Implicit(this.Profile.Species), this.Profile.Sex, prototype, this._prototypeManager))
      nullable = !this._markingManager.MustMatchSkin(ProtoId<SpeciesPrototype>.op_Implicit(this.Profile.Species), HumanoidVisualLayers.Hair, out float _, this._prototypeManager) ? new Color?(this.Profile.Appearance.HairColor) : new Color?(this.Profile.Appearance.SkinColor);
    if (nullable.HasValue)
      this.Markings.HairMarking = new Marking(this.Profile.Appearance.HairStyleId, new List<Color>()
      {
        nullable.Value
      });
    else
      this.Markings.HairMarking = (Marking) null;
  }

  private void UpdateCMarkingsFacialHair()
  {
    if (this.Profile == null)
      return;
