        ((BaseButton) this.CompactFelinidButton).Disabled = false;
        ((Control) this.CompactFelinidButton).ToolTip = (string) null;
      }
      else
      {
        this.CompactFelinidButton.Text = "LOCKED " + str;
        ((BaseButton) this.CompactFelinidButton).Disabled = true;
        ((Control) this.CompactFelinidButton).ToolTip = Loc.GetString("pubg-species-locked-tier5");
      }
    }
    else
      ((Control) this.CompactFelinidButton).Visible = false;
    ProtoId<SpeciesPrototype>? species = this.Profile?.Species;
    ProtoId<SpeciesPrototype>? nullable = ProtoId<SpeciesPrototype>.op_Implicit("Felinid");
    bool flag = species.HasValue != nullable.HasValue || species.HasValue && ProtoId<SpeciesPrototype>.op_Inequality(species.GetValueOrDefault(), nullable.GetValueOrDefault());
