  private async void ImportProfile()
  {
    if (this._exporting || !this.CharacterSlot.HasValue || this.Profile == null)
      return;
    this.StartExport();
    Stream stream = await this._dialogManager.OpenFile(new FileDialogFilters(new FileDialogFilters.Group[1]
    {
      new FileDialogFilters.Group(new string[1]{ "yml" })
    }), FileAccess.ReadWrite, new FileShare?());
    object obj = (object) null;
    int num = 0;
    try
    {
      if (stream == null)
      {
        this.EndExport();
      }
      else
      {
        try
        {
          HumanoidCharacterProfile profile1 = this._entManager.System<HumanoidAppearanceSystem>().FromStream(stream, ((ISharedPlayerManager) this._playerManager).LocalSession);
          HumanoidCharacterProfile profile2 = this.Profile;
          this.SetProfile(profile1, this.CharacterSlot);
          this.IsDirty = !profile1.MemberwiseEquals((ICharacterProfile) profile2);
        }
        catch (Exception ex)
        {
          this._sawmill.Error("Error when importing profile\n" + ex.StackTrace);
        }
        finally
        {
          this.EndExport();
        }
      }
      num = 1;
    }
    catch (object ex)
    {
      obj = ex;
    }
    if (stream != null)
      await stream.DisposeAsync();
    object obj1 = obj;
    if (obj1 != null)
    {
      if (!(obj1 is Exception source))
        throw obj1;
      ExceptionDispatchInfo.Capture(source).Throw();
    }
    if (num != 1)
    {
      obj = (object) null;
      throw null;
    }
  }

  private async void ExportProfile()
  {
    if (this.Profile == null || this._exporting)
      return;
    this.StartExport();
    (Stream, bool)? file = await this._dialogManager.SaveFile(new FileDialogFilters(new FileDialogFilters.Group[1]
    {
      new FileDialogFilters.Group(new string[1]{ "yml" })
    }), true, FileAccess.ReadWrite, FileShare.None);
    if (!file.HasValue)
    {
      this.EndExport();
    }
    else
    {
      try
      {
        await using (StreamWriter streamWriter = new StreamWriter(file.Value.Item1))
          this._entManager.System<HumanoidAppearanceSystem>().ToDataNode(this.Profile).Write((TextWriter) streamWriter);
      }
      catch (Exception ex)
      {
        this._sawmill.Error("Error when exporting profile\n" + ex.StackTrace);
      }
      finally
      {
        this.EndExport();
        await file.Value.Item1.DisposeAsync();
      }
    }
  }

  private void StartExport()
  {
    this._exporting = true;
    ((BaseButton) this.ImportButton).Disabled = true;
    ((BaseButton) this.ExportButton).Disabled = true;
  }

  private void EndExport()
  {
    this._exporting = false;
    ((BaseButton) this.ImportButton).Disabled = false;
    ((BaseButton) this.ExportButton).Disabled = false;
  }

